const items = $input.all();
const seen = new Set();
const cleaned = [];

for (const item of items) {
  const text = item.json.data || '';

  // Skip blocked pages
  if (
    text.length < 500 ||
    text.includes('error 403') ||
    text.includes('Checking your browser') ||
    text.includes('CAPTCHA') ||
    text.includes('Just a moment')
  ) continue;

  const fingerprint = text.substring(0, 100);
  if (seen.has(fingerprint)) continue;
  seen.add(fingerprint);

  cleaned.push({
    json: {
      scrapedContent: text.replace(/\s+/g, ' ').trim().substring(0, 5000),
      keyword: $('Extract Top URLs').item.json.keyword
    }
  });
}

if (cleaned.length === 0) {
  return [{ json: { scrapedContent: 'No content available', keyword: '' } }];
}

return cleaned;

const data = $input.first().json;
const organicResults = data.organic_results || [];

const urls = organicResults
  .filter(r => r.link &&
    !r.link.includes('youtube.com') &&
    !r.link.includes('facebook.com') &&
    !r.link.includes('.pdf')
  )
  .slice(0, 7)
  .map(r => ({
    json: {
      url: r.link,
      title: r.title,
      snippet: r.snippet,
      position: r.position,
      keyword: $('Google search').first().json.search_parameters.q
    }
  }));

return urls;

const keywords = $input.first().json.body.keywords;

return keywords.map((keyword, index) => ({
  json: {
    jobId: `job_${Date.now()}_${index}`,
    keyword: keyword.trim(),
    startTime: new Date().toISOString()
  }
}));

const item = $input.first().json;

// Parse the JSON from AI output
let prompts = {};
try {
  const raw = item.output.replace(/```json|```/g, '').trim();
  prompts = JSON.parse(raw);
} catch(e) {
  // Fallback - use empty objects
  prompts = {
    featuredImage: { prompt: "", searchKeyword: "education" },
    inPostImage1: { prompt: "", searchKeyword: "students" },
    inPostImage2: { prompt: "", searchKeyword: "university" }
  };
}

// Return 3 separate items
return [
  { json: { prompt: prompts.featuredImage, type: "featuredImage" } },
  { json: { prompt: prompts.inPostImage1, type: "inPostImage1" } },
  { json: { prompt: prompts.inPostImage2, type: "inPostImage2" } }
];

const item = $input.first().json;

let metadata = {};
try {
  const raw = item.output.replace(/```json|```/g, '').trim();
  metadata = JSON.parse(raw);
} catch(e) {
  metadata = {};
}

const articleSchema = {
  "@context": "https://schema.org",
  "@type": "Article",
  "headline": metadata.seoTitle || '',
  "description": metadata.metaDescription || '',
  "author": {
    "@type": "Organization",
    "name": "ScholarZed"
  },
  "publisher": {
    "@type": "Organization",
    "name": "ScholarZed",
    "url": "https://scholarzed.com"
  },
  "datePublished": new Date().toISOString(),
  "dateModified": new Date().toISOString()
};

return [{
  json: {
    ...metadata,
    articleSchema: JSON.stringify(articleSchema),
    faqSchema: '',
    article: ''
  }
}];

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // Pick a different result index for each image
  const photoResults = item.json.results;

  if (!photoResults || photoResults.length === 0) {
    continue;
  }

  // Use different index for each image: 0, 1, 2
  const index = i % photoResults.length;
  const photo = photoResults[index];

  if (!photo || !photo.urls) {
    continue;
  }

  results.push({
    json: {
      imageUrl: photo.urls.regular,
      altText: photo.alt_description || 'education image',
      photographer: photo.user.name,
      fileName: `seo-image-${photo.id}.jpg`
    }
  });
}

// Fallback if no images found
if (results.length === 0) {
  return [{
    json: {
      imageUrl: 'https://images.unsplash.com/photo-1527613426441-4da17471b66d?w=1080',
      altText: 'education image',
      photographer: 'Unsplash',
      fileName: 'seo-image-fallback.jpg'
    }
  }];
}

return results;

const items = $input.all();
return [{
  json: {
    featured_media_id: items[0]?.json?.id || 0,
    inpost_image1_id: items[1]?.json?.id || 0,
    inpost_image2_id: items[2]?.json?.id || 0,
    featured_media_url: items[0]?.json?.source_url || '',
    inpost_image1_url: items[1]?.json?.source_url || '',
    inpost_image2_url: items[2]?.json?.source_url || '',
    total_images: items.length
  }
}];

