const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      url: item.json.url,
      keyword: item.json.keyword,
      jinaUrl: `https://r.jina.ai/${item.json.url}`,
      directUrl: item.json.url
    }
  });
}

return results;

// Get article content - try SEO Editor first (QA failed path), then Human Rewriter (QA passed path)
let mergeOutput = '';
try {
  const seoEditorOutput = $('SEO Editor').first().json.output;
  if (seoEditorOutput && seoEditorOutput.length > 500) {
    mergeOutput = seoEditorOutput;
  }
} catch(e) {}
if (!mergeOutput) {
  try {
    const humanRewriterOutput = $('Human Rewriter ').first().json.output;
    if (humanRewriterOutput && humanRewriterOutput.length > 500) {
      mergeOutput = humanRewriterOutput;
    }
  } catch(e) {}
}
let seo = {};
let schemaData = {};
let media = {};
let keyword = '';
try {
  schemaData = $('Schema Builder').first().json;
} catch(e) {}
try {
  const seoRaw = $('SEO Optimizer').first().json.output;
  const cleaned = seoRaw.replace(/```json|```/g, '').trim();
  seo = JSON.parse(cleaned);
} catch(e) {
  seo = schemaData;
}
try {
  media = $('Collect Media Id').first().json;
} catch(e) {}
try {
  keyword = $('Extract Keywords').first().json.keyword;
} catch(e) {}

// Inject inpost images into content
function injectImages(content, img1Id, img1Url, img2Id, img2Url) {
  if (!content) return content;
  const img1Html = img1Url ? `\n\n<figure class="wp-block-image size-large"><img src="${img1Url}" class="wp-image-${img1Id}" alt="" /></figure>\n\n` : '';
  const img2Html = img2Url ? `\n\n<figure class="wp-block-image size-large"><img src="${img2Url}" class="wp-image-${img2Id}" alt="" /></figure>\n\n` : '';
  const h2Regex = /^## .+$/gm;
  let h2Matches = [...content.matchAll(h2Regex)];
  if (h2Matches.length >= 3 && img1Html) {
    const pos = h2Matches[2].index;
    content = content.slice(0, pos) + img1Html + content.slice(pos);
  }
  h2Matches = [...content.matchAll(h2Regex)];
  if (h2Matches.length >= 5 && img2Html) {
    const pos = h2Matches[4].index;
    content = content.slice(0, pos) + img2Html + content.slice(pos);
  }
  return content;
}

return [{
  json: {
    title: schemaData.seoTitle || seo.seoTitle || keyword,
    slug: schemaData.slug || seo.slug || '',
    excerpt: schemaData.excerpt || seo.excerpt || '',
    metaDescription: schemaData.metaDescription || seo.metaDescription || '',
    focusKeyphrase: schemaData.focusKeyphrase || seo.focusKeyphrase || keyword,
    categories: schemaData.categories || seo.categories || [],
    tags: schemaData.tags || seo.tags || [],
    content: injectImages(mergeOutput, media.inpost_image1_id, media.inpost_image1_url, media.inpost_image2_id, media.inpost_image2_url),
    featured_media_id: media.featured_media_id || 0,
    inpost_image1_id: media.inpost_image1_id || 0,
    inpost_image2_id: media.inpost_image2_id || 0,
    keyword: keyword
  }
}];

const results = [];
for (const item of $input.all()) {
  let content = item.json.content || '';

  // Fix year
  content = content.replace(/2025\/2026/g, '2026/2027');
  content = content.replace(/2024\/2025/g, '2026/2027');
  content = content.replace(/2024/g, '2026');
  content = content.replace(/2025/g, '2026');

  // Convert markdown tables FIRST
  content = content.replace(/(\|.+\|[ \t]*\n)([ \t]*\|[-:| \t]+\|[ \t]*\n)((?:[ \t]*\|.+\|[ \t]*\n?)*)/gm, (match) => {
    const rows = match.trim().split('\n').filter(r => r.trim());
    const headers = rows[0].split('|').filter(cell => cell.trim() !== '');
    const body = rows.slice(2);
    let html = '<table>\n<thead>\n<tr>\n';
    headers.forEach(h => { html += `<th>${h.trim()}</th>\n`; });
    html += '</tr>\n</thead>\n<tbody>\n';
    body.forEach(row => {
      const cells = row.split('|').filter(cell => cell.trim() !== '');
      if (cells.length > 0) {
        html += '<tr>\n';
        cells.forEach(cell => { html += `<td>${cell.trim()}</td>\n`; });
        html += '</tr>\n';
      }
    });
    html += '</tbody>\n</table>\n';
    return html;
  });

  // Convert headings
  content = content.replace(/^#### (.+)$/gm, '<h4>$1</h4>');
  content = content.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  content = content.replace(/^## (.+)$/gm, '<h2>$1</h2>');
  content = content.replace(/^# (.+)$/gm, '<h1>$1</h1>');

  // Remove duplicate H1
  content = content.replace(/<h1>.*?<\/h1>/i, '');

  // Convert bold
  content = content.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');

  // Convert italic *text*
  content = content.replace(/\*([^*\n]+)\*/g, '<em>$1</em>');

  // Convert links [text](url)
  content = content.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

  // Convert blockquotes
  content = content.replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>');

  // Convert horizontal rules
  content = content.replace(/^---$/gm, '<hr>');

  // Convert asterisk bullet lists (* item)
  content = content.replace(/(?:^|\n)((?:\* .+\n?)+)/gm, (match, list) => {
    const listItems = list.trim().split('\n').map(line => {
      return `<li>${line.replace(/^\* /, '').trim()}</li>`;
    }).join('\n');
    return `\n<ul>\n${listItems}\n</ul>\n`;
  });

  // Convert indented dash lists (   - item)
  content = content.replace(/(?:^|\n)((?:[ \t]+-[ \t]+.+\n?)+)/gm, (match, list) => {
    const listItems = list.trim().split('\n').map(line => {
      return `<li>${line.replace(/^[ \t]+-[ \t]+/, '').trim()}</li>`;
    }).join('\n');
    return `\n<ul>\n${listItems}\n</ul>\n`;
  });

  // Convert dash bullet lists (- item)
  content = content.replace(/(?:^|\n)((?:- .+\n?)+)/gm, (match, list) => {
    const listItems = list.trim().split('\n').map(line => {
      return `<li>${line.replace(/^- /, '').trim()}</li>`;
    }).join('\n');
    return `\n<ul>\n${listItems}\n</ul>\n`;
  });

  // Convert numbered lists
  content = content.replace(/(?:^|\n)((?:\d+\. .+\n?)+)/gm, (match, list) => {
    const listItems = list.trim().split('\n').map(line => {
      return `<li>${line.replace(/^\d+\. /, '').trim()}</li>`;
    }).join('\n');
    return `\n<ol>\n${listItems}\n</ol>\n`;
  });

  // Remove ALL leftover dashes
  content = content.replace(/^[ \t]*–[ \t]/gm, '');
  content = content.replace(/^[ \t]*-[ \t](?!-)/gm, '');
  content = content.replace(/^[ \t]*—[ \t]/gm, '');

  results.push({
    json: { ...item.json, content }
  });
}
return results;

