const briefOutput = $input.first().json.output;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://scholarzed.com/wp-json/wp/v2/posts',
  qs: {
    per_page: 50,
    status: 'publish',
    _fields: 'title,link'
  }
});

const postsList = response.map(p => `- ${p.title.rendered}: ${p.link}`).join('\n');

return [{
  json: {
    output: briefOutput + '\n\nEXISTING SCHOLARZED.COM ARTICLES FOR INTERNAL LINKING:\n' +
    '⚠️ RULES: Use ONLY these URLs. Use the exact article TITLE as anchor text. NEVER use a different description as anchor text. NEVER modify or guess any URL.\n\n' +
    postsList
  }
}];
